enum TariTypeTag {
  Text(0),
  Utxo(1),
  Commitment(2),
  U64(3),
  I64(4);

  final int value;
  const TariTypeTag(this.value);

  static TariTypeTag fromValue(int value) => switch (value) {
        0 => Text,
        1 => Utxo,
        2 => Commitment,
        3 => U64,
        4 => I64,
        _ => throw ArgumentError("Unknown value for TariTypeTag: $value"),
      };
}

enum TariUtxoSort {
  ValueAsc(0),
  ValueDesc(1),
  MinedHeightAsc(2),
  MinedHeightDesc(3);

  final int value;
  const TariUtxoSort(this.value);

  static TariUtxoSort fromValue(int value) => switch (value) {
        0 => ValueAsc,
        1 => ValueDesc,
        2 => MinedHeightAsc,
        3 => MinedHeightDesc,
        _ => throw ArgumentError("Unknown value for TariUtxoSort: $value"),
      };
}

