/// The transaction kernel tracks the excess for a given transaction. For an explanation of what the excess is, and
/// why it is necessary, refer to the
/// [Mimblewimble TLU post](https://tlu.tarilabs.com/protocols/mimblewimble-1/sources/PITCHME.link.html?highlight=mimblewimble#mimblewimble).
/// The kernel also tracks other transaction metadata, such as the lock height for the transaction (i.e. the earliest
/// this transaction can be mined) and the transaction fee, in cleartext.
final class TransactionKernel extends ffi.Opaque {}

final class TransactionSendStatus extends ffi.Opaque {}

final class TransportConfig extends ffi.Opaque {}

/// An unblinded output is one where the value and spending key (blinding factor) are known. This can be used to
/// build both inputs and outputs (every input comes from an output). This is only used for import and export where
/// serialization is important.
final class UnblindedOutput extends ffi.Opaque {}

/// -------------------------------- Vector ------------------------------------------------ ///
final class TariVector extends ffi.Struct {
  @ffi.UnsignedInt()
  external int tagAsInt;

  TariTypeTag get tag => TariTypeTag.fromValue(tagAsInt);

  @ffi.UintPtr()
  external int len;

  @ffi.UintPtr()
  external int cap;

  external ffi.Pointer<ffi.Void> ptr;
}

final class TariCoinPreview extends ffi.Struct {
  external ffi.Pointer<TariVector> expected_outputs;

  @ffi.Uint64()
  external int fee;
}

final class TariUtxo extends ffi.Struct {
  external ffi.Pointer<ffi.Char> commitment;

  @ffi.Uint64()
  external int value;

  @ffi.Uint64()
  external int mined_height;

  @ffi.Uint64()
  external int mined_timestamp;

  @ffi.Uint64()
  external int lock_height;

  @ffi.Uint8()
  external int status;

  external ffi.Pointer<ffi.Char> coinbase_extra;

  external ffi.Pointer<ffi.Char> raw_payment_id;

  external ffi.Pointer<ffi.Char> user_payment_id;

  external ffi.Pointer<ffi.Char> mined_in_block;
}

